import React, { useState, useRef } from 'react';
import './App.css';

function App() {
    const [objects, setObjects] = useState([]);
    const [draggingId, setDraggingId] = useState(null);
    const [offset, setOffset] = useState({ x: 0, y: 0 });

    function newObject() {
        setObjects([...objects, { id: Date.now(), left: 0, top: 0 }]);
    }

    function mouseDownOnObject(id) {
        setDraggingId(id);
    }

    function objectDragging(e) {
        if (!draggingId) return;

        const canvasRef = useRef(null);
        const canvasRect = canvasRef.current.getBoundingClientRect();
        const canvasWidth = 800;
        const canvasHeight = 600;
        const objectSize = 50;

        const offsetX = offset.x;
        const offsetY = offset.y;

        let newLeft = e.clientX - canvasRect.left - offsetX;
        let newTop = e.clientY - canvasRect.top - offsetY;

        newLeft = Math.max(0, Math.min(newLeft, canvasWidth - objectSize));
        newTop = Math.max(0, Math.min(newTop, canvasHeight - objectSize));

        setObjects((prevObjects) =>
            prevObjects.map((obj) =>
                obj.id === draggingId
                    ? { ...obj, left: newLeft, top: newTop }
                    : obj,
            ),
        );
    }

    function stoppedDragging(e) {
        setDraggingId(null);
    }
    return (
        <div className="app-container">
            <header className="header">
                <h1>🎵 Sound Landscape</h1>
            </header>
            <div className="main">
                <aside className="sidebar">
                    <button onClick={newObject}>Добавить объект</button>
                </aside>
                <div
                    className="canvas-container"
                    ref={canvasRef}
                    onMouseMove={(e) => objectDragging(e)}
                    onMouseUp={(e) => stoppedDragging(e)}
                    style={{
                        position: 'relative',
                    }}
                >
                    {objects.map((obj) => (
                        <div
                            onMouseDown={(e) => mouseDownOnObject(obj.id)}
                            className="obj"
                            key={obj.id}
                            style={{
                                position: 'absolute',
                                left: obj.left,
                                top: obj.top,
                            }}
                        ></div>
                    ))}
                </div>
            </div>
        </div>
    );
}

export default App;
